const validateForm = async ({
  name,
  eventType,
}: {
  name: FieldPath<TFieldValues> | FieldPath<TFieldValues>[] | undefined;
  eventType: ValidateFormEventType;
}) => {
  if (props.validate) {
    const result = await props.validate({
      formValues: _formValues,
      formState: _formState,
      name,
      eventType,
    });

    if (isObject(result)) {
      for (const key in result) {
        const error = result[key];

        if (error) {
          setError(`${FORM_ERROR_TYPE}.${key}`, {
            message: isString(error.message) ? error.message : '',
            type: error.type || INPUT_VALIDATION_RULES.validate,
          });
        }
      }
    } else if (isString(result) || !result) {
      setError(FORM_ERROR_TYPE, {
        message: result || '',
        type: INPUT_VALIDATION_RULES.validate,
      });
    } else {
      clearErrors(FORM_ERROR_TYPE);
    }

    return result;
  }

  return true;
};

const executeBuiltInValidation = async ({
  fields,
  onlyCheckValid,
  name,
  eventType,
  context = {
    valid: true,
    runRootValidation: false,
  },
}: {
  fields: FieldRefs;
  onlyCheckValid?: boolean;
  name?: FieldPath<TFieldValues> | FieldPath<TFieldValues>[];
  eventType: ValidateFormEventType;
  context?: {
    valid: boolean;
    runRootValidation?: boolean;
  };
}) => {
  if (props.validate) {
    context.runRootValidation = true;
    const result = await validateForm({
      name,
      eventType,
    });

    if (!result) {
      context.valid = false;

      if (onlyCheckValid) {
        return context.valid;
      }
    }
  }

  for (const name in fields) {
    const field = fields[name];

    if (field) {
      const { _f, ...fieldValue } = field as Field;

      if (_f) {
        const isFieldArrayRoot = _names.array.has(_f.name);
        const isPromiseFunction =
          field._f && hasPromiseValidation((field as Field)._f);
        const shouldTrackIsValidatingState =
          _proxyFormState.validatingFields ||
          _proxyFormState.isValidating ||
          _proxySubscribeFormState.validatingFields ||
          _proxySubscribeFormState.isValidating;

        if (isPromiseFunction && shouldTrackIsValidatingState) {
          _updateIsValidating([_f.name], true);
        }

        const fieldError = await validateField(
          field as Field,
          _names.disabled,
          _formValues,
          shouldDisplayAllAssociatedErrors,
          _options.shouldUseNativeValidation && !onlyCheckValid,
          isFieldArrayRoot,
        );

        if (isPromiseFunction && shouldTrackIsValidatingState) {
          _updateIsValidating([_f.name]);
        }

        if (fieldError[_f.name]) {
          context.valid = false;

          if (onlyCheckValid) {
            break;
          }
        }

        !onlyCheckValid &&
          (get(fieldError, _f.name)
            ? isFieldArrayRoot
              ? updateFieldArrayRootError(
                  _formState.errors,
                  fieldError,
                  _f.name,
                )
              : set(_formState.errors, _f.name, fieldError[_f.name])
            : unset(_formState.errors, _f.name));

        if (props.shouldUseNativeValidation && fieldError[_f.name]) {
          break;
        }
      }

      !isEmptyObject(fieldValue) &&
        (await executeBuiltInValidation({
          context,
          onlyCheckValid,
          fields: fieldValue,
          name: name as FieldPath<TFieldValues>,
          eventType,
        }));
    }
  }

  return context.valid;
};

